{"code": "import json
import pandas as pd
from collections import defaultdict
import os

# Load patent data
data_file_path = 'var_functions.query_db:104.json'
with open(data_file_path, 'r') as f:
    patents = json.load(f)

print(f"Loaded {len(patents)} patent records")

# Filter for German patents in second half 2019
german_h2_2019 = []
months_full = ['July', 'August', 'September', 'October', 'November', 'December']
months_abbr = ['Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec']

for p in patents:
    info = p['Patents_info']
    if 'from DE' not in info and 'In DE,' not in info:
        continue

    gdate = p['grant_date']
    if '2019' not in gdate:
        continue

    is_h2 = False
    for m in months_full:
        if m in gdate:
            is_h2 = True
            break
    if not is_h2:
        for m in months_abbr:
            if m in gdate:
                is_h2 = True
                break

    if is_h2:
        german_h2_2019.append(p)

print(f"German patents in H2 2019: {len(german_h2_2019)}")

# Extract CPC level 4 codes and count by month
cpc_counts = defaultdict(lambda: [0,0,0,0,0,0])  # July to Dec

for p in german_h2_2019:
    cpc_str = p['cpc']
    if len(cpc_str) < 10:
        continue

    cpc_list = json.loads(cpc_str)

    # Find month
    month = 7
    for i,m in enumerate(months_full):
        if m in p['grant_date']:
            month = i+7
            break
    if month == 7:
        for i,m in enumerate(months_abbr):
            if m in p['grant_date']:
                month = i+7
                break

    for entry in cpc_list:
        code = entry.get('code', '')
        parts = code.split('/')
        if len(parts) == 2 and len(parts[0]) >= 4 and len(parts[1]) >= 2:
            level4 = parts[0][:4] + '/' + parts[1][:2]
            cpc_counts[level4][month-7] += 1

print(f"Unique CPC level 4 codes: {len(cpc_counts)}")

# Calculate EMA (smoothing factor 0.1)
results = []
for code, counts in cpc_counts.items():
    if sum(counts) == 0:
        continue
    ema = [float(counts[0])]
    for i in range(1, len(counts)):
        ema.append(0.1 * counts[i] + 0.9 * ema[-1])
    max_ema = max(ema)
    best_month = ema.index(max_ema) + 7
    results.append({
        'code': code,
        'max_ema': round(max_ema, 2),
        'best_month': best_month,
        'counts': [int(x) for x in counts],
        'ema_series': [round(x, 2) for x in ema]
    })

results.sort(key=lambda x: x['max_ema'], reverse=True)

print(f"\nTop 15 CPC codes by EMA:")
for i in range(min(15, len(results))):
    r = results[i]
    print(f"{i+1}. {r['code']}: EMA={r['max_ema']}, Best month={r['best_month']}, Counts={r['counts']}")

# Get top codes for definition lookup
top_codes = [r['code'] for r in results[:15]]
print(f"\nTop 15 codes for lookup: {top_codes}")"}

